INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", "2030/12/17 14:59:59", 0.0, 0.0, 401, 102301, 10046, 24, "2020/07/31 12:00:00", 2, "アヤネ", 2, 24001, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", "2030/12/17 14:59:59", 2.21, 0.0, 402, 102301, 10046, 24, "2020/07/31 12:00:00", 1, "アヤネ", 2, 24002, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", "2030/12/17 14:59:59", 0.0, 0.0, 403, 102301, 10046, 24, "2020/07/31 12:00:00", 2, "アヤネ", 2, 24003, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", "2030/12/17 14:59:59", 1.99, 0.0, 701, 192201, 10046, 24, "2020/07/31 12:00:00", 2, "アサヒ", 1, 24004, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", "2030/12/17 14:59:59", 2.21, 0.0, 702, 192201, 10046, 24, "2020/07/31 12:00:00", 1, "アサヒ", 2, 24005, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", "2030/12/17 14:59:59", 3.33, 0.0, 703, 192201, 10046, 24, "2020/07/31 12:00:00", 2, "アサヒ", 1, 24006, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", "2030/12/17 14:59:59", 0.0, 0.0, 801, 192301, 10046, 24, "2020/07/31 12:00:00", 2, "部員３", 2, 24007, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", "2030/12/17 14:59:59", 2.68, 0.0, 802, 192301, 10046, 24, "2020/07/31 12:00:00", 1, "部員３", 2, 24008, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", "2030/12/17 14:59:59", 0.0, 0.0, 803, 192301, 10046, 24, "2020/07/31 12:00:00", 2, "部員３", 2, 24009, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("やった！", "2030/12/17 14:59:59", 0.0, 0.0, 501, 192501, 10046, 24, "2020/07/31 12:00:00", 1, "", 1, 24010, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("勝ったよ！", "2030/12/17 14:59:59", 0.0, 0.0, 502, 192501, 10046, 24, "2020/07/31 12:00:00", 1, "", 1, 24011, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("いい調子！", "2030/12/17 14:59:59", 0.0, 0.0, 503, 192501, 10046, 24, "2020/07/31 12:00:00", 1, "", 1, 24012, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", "2030/12/17 14:59:59", 5.33, 0.0, 111, 113501, 10046, 24, "2020/07/31 12:00:00", 6, "ミサト", 2, 24013, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", "2030/12/17 14:59:59", 6.85, 0.0, 112, 113501, 10046, 24, "2020/07/31 12:00:00", 1, "ミサト", 2, 24014, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", "2030/12/17 14:59:59", 3.0, 0.0, 113, 113501, 10046, 24, "2020/07/31 12:00:00", 1, "ミサト", 2, 24015, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", "2030/12/17 14:59:59", 6.11, 0.0, 611, 192401, 10046, 24, "2020/07/31 12:00:00", 1, "ダイチ", 2, 24016, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", "2030/12/17 14:59:59", 6.75, 0.0, 612, 192401, 10046, 24, "2020/07/31 12:00:00", 1, "ダイチ", 2, 24017, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", "2030/12/17 14:59:59", 0.0, 0.0, 613, 192401, 10046, 24, "2020/07/31 12:00:00", 2, "ダイチ", 2, 24018, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", "2030/12/17 14:59:59", 4.52, 0.0, 211, 113401, 10046, 24, "2020/07/31 12:00:00", 2, "ハツネ", 1, 24019, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", "2030/12/17 14:59:59", 3.89, 0.0, 212, 113401, 10046, 24, "2020/07/31 12:00:00", 2, "ハツネ", 1, 24020, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", "2030/12/17 14:59:59", 13.49, 0.0, 213, 113401, 10046, 24, "2020/07/31 12:00:00", 1, "ハツネ", 2, 24021, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", "2030/12/17 14:59:59", 3.17, 0.0, 311, 106501, 10046, 24, "2020/07/31 12:00:00", 1, "カヤ", 2, 24022, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", "2030/12/17 14:59:59", 4.42, 0.0, 312, 106501, 10046, 24, "2020/07/31 12:00:00", 1, "カヤ", 2, 24023, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", "2030/12/17 14:59:59", 2.89, 0.0, 313, 106501, 10046, 24, "2020/07/31 12:00:00", 6, "カヤ", 1, 24024, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", "2030/12/17 14:59:59", 3.71, 0.0, 421, 102301, 10046, 24, "2020/07/31 12:00:00", 4, "アヤネ", 3, 24025, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", "2030/12/17 14:59:59", 5.1, 0.0, 721, 192201, 10046, 24, "2020/07/31 12:00:00", 2, "アサヒ", 1, 24026, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", "2030/12/17 14:59:59", 4.34, 0.0, 821, 192301, 10046, 24, "2020/07/31 12:00:00", 1, "部員３", 3, 24027, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("いい勝負だったよ\nまたやろうね", "2030/12/17 14:59:59", 0.0, 0.0, 521, 192501, 10046, 24, "2020/07/31 12:00:00", 1, "", 1, 24028, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", "2030/12/17 14:59:59", 5.62, 0.0, 101, 113501, 10046, 24, "2020/07/31 12:00:00", 1, "ミサト", 2, 24029, -360.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", "2030/12/17 14:59:59", 9.58, 0.0, 102, 113501, 10046, 24, "2020/07/31 12:00:00", 1, "ミサト", 2, 24030, -360.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", "2030/12/17 14:59:59", 0.0, 0.0, 103, 113501, 10046, 24, "2020/07/31 12:00:00", 2, "ミサト", 2, 24031, -360.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", "2030/12/17 14:59:59", 9.13, 0.0, 104, 113501, 10046, 24, "2020/07/31 12:00:00", 2, "ミサト", 1, 24032, -360.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", "2030/12/17 14:59:59", 8.27, 0.0, 105, 113501, 10046, 24, "2020/07/31 12:00:00", 1, "ミサト", 2, 24033, -360.0);
